#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char Q[100005];
        scanf("%s", Q);
        int L = strlen(Q);
        int prefLen = L < 9 ? L : 9;
        char prefStr[10];
        memcpy(prefStr, Q, prefLen);
        prefStr[prefLen] = '\0';
        long long pref = atoll(prefStr);
        int found = 0;
        long long startLow = pref > 9 ? pref - 9 : 1;
        for (long long start = startLow; start <= pref + 9 && !found; ++start) {
            // build temporary string S
            int needed = L + 10;
            char *S = (char *)malloc(needed + 1);
            S[0] = '\0';
            int curLen = 0;
            long long cur = start;
            while (curLen < needed) {
                char buf[12];
                int len = sprintf(buf, "%lld", cur);
                if (curLen + len > needed) {
                    // truncate if exceeds needed (still safe for strstr)
                    buf[needed - curLen] = '\0';
                    len = needed - curLen;
                }
                strcat(S, buf);
                curLen += len;
                ++cur;
            }
            if (strstr(S, Q) != NULL) found = 1;
            free(S);
        }
        printf(found ? "YES\n" : "NO\n");
    }
    return 0;
}

