import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String Q = br.readLine().trim();
            int L = Q.length();
            int prefLen = Math.min(9, L);
            long pref = Long.parseLong(Q.substring(0, prefLen));
            boolean ok = false;
            long startLow = pref > 9 ? pref - 9 : 1;
            for (long start = startLow; start <= pref + 9 && !ok; ++start) {
                StringBuilder sb = new StringBuilder(L + 10);
                long cur = start;
                while (sb.length() < L + 10) {
                    sb.append(cur);
                    ++cur;
                }
                if (sb.indexOf(Q) != -1) ok = true;
            }
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

